private void xrTableCell30_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    decimal fChicks = 0;
    decimal mChicks = 0;

    if (GetCurrentColumnValue("FChicks") != null)
        fChicks = Convert.ToDecimal(GetCurrentColumnValue("FChicks"));

    if (GetCurrentColumnValue("MChicks") != null)
        mChicks = Convert.ToDecimal(GetCurrentColumnValue("MChicks"));

    decimal result = fChicks + mChicks;

    XRTableCell cell = sender as XRTableCell;
    cell.Text = result.ToString("0"); // no decimals, adjust format if needed

    }

private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    decimal fChicks = 0;
    decimal mChicks = 0;

    if (GetCurrentColumnValue("FChicks") != null)
        fChicks = Convert.ToDecimal(GetCurrentColumnValue("FChicks"));

    if (GetCurrentColumnValue("MChicks") != null)
        mChicks = Convert.ToDecimal(GetCurrentColumnValue("MChicks"));

    groupSumChicks += (fChicks + mChicks);
     // --- New logic for culls + dead ---
    decimal fCulls = 0;
    decimal mCulls = 0;
    decimal fDead  = 0;
    decimal mDead  = 0;

    if (GetCurrentColumnValue("FCulls") != null)
        fCulls = Convert.ToDecimal(GetCurrentColumnValue("FCulls"));

    if (GetCurrentColumnValue("MCulls") != null)
        mCulls = Convert.ToDecimal(GetCurrentColumnValue("MCulls"));

    if (GetCurrentColumnValue("FDead") != null)
        fDead = Convert.ToDecimal(GetCurrentColumnValue("FDead"));

    if (GetCurrentColumnValue("MDead") != null)
        mDead = Convert.ToDecimal(GetCurrentColumnValue("MDead"));

    groupSumCullsDead += (fCulls + mCulls + fDead + mDead);
    // -- new logic for culls and dead iwthout specify the gender
     decimal Culls = 0;
    decimal Dead= 0;

    if (GetCurrentColumnValue("Culls") != null)
        Culls = Convert.ToDecimal(GetCurrentColumnValue("Culls"));

    if (GetCurrentColumnValue("Dead") != null)
        Dead= Convert.ToDecimal(GetCurrentColumnValue("Dead"));

    groupSumOfCullsDead += (Culls + Dead);

      // -- new logic for total Loss
       decimal UnHatEggs= 0;
       decimal DestroyedEggs= 0;

        if (GetCurrentColumnValue("UnHatEggs") != null)
            UnHatEggs= Convert.ToDecimal(GetCurrentColumnValue("UnHatEggs"));

        if (GetCurrentColumnValue("DestroyedEggs") != null)
            DestroyedEggs= Convert.ToDecimal(GetCurrentColumnValue("DestroyedEggs"));
        groupSumOftotalCullsDead = groupSumCullsDead  + groupSumOfCullsDead 
        groupSumOfTotalLoss += (UnHatEggs+ DestroyedEggs);
        groupresultOfTotalLoss = groupSumOftotalCullsDead  + groupSumOfTotalLoss 
          // --- New logic for total
        decimal Chicks  = 0;
        if (GetCurrentColumnValue("Chicks") != null)
        Chicks = Convert.ToDecimal(GetCurrentColumnValue("Chicks"));
        groupresultOfTotal =  Chicks  + groupSumOfTotalLoss + groupSumCullsDead  + groupSumChicks 



}

